mapper.update:
 UPDATE /* LgsNstepIfMapper.updLinkData */
		LGS_TELECOM_IF
    SET
		CHNG_ID = #{userId, jdbcType=VARCHAR}
	  , CHNG_DTTM = SYSDATE
	  , LGS_PRCS_DT = TO_CHAR(SYSDATE,'YYYYMMDD')
	  , LGS_PRCS_TM = TO_CHAR(SYSDATE,'HH24MMSS')
		, LGS_PRCS_YN = #{procStatCd, jdbcType=VARCHAR} 
		, LGS_REMARK = #{procCd, jdbcType=VARCHAR}  
   WHERE IF_QUE_NUM = #{ifQueNum, jdbcType=VARCHAR}

mapper.insert:
  MERGE  /* LgsNstepIfMapper.insChckDataInfo */
   INTO  LGS_OPEN_CHCK_INFO
  USING  DUAL
	 ON  (  IF_QUE_NUM = #{ifQueNum, jdbcType=VARCHAR}
			AND CONTRACT_NUM = #{contractNum, jdbcType=VARCHAR}
		 )

   WHEN  MATCHED THEN

		 UPDATE
			SET   APPL_STRT_DTTM = #{applStrtDttm, jdbcType=VARCHAR}
				, PROC_STAT_CD = #{procCd, jdbcType=VARCHAR}
				, APPL_EVNT_CD = #{aplEvntCd, jdbcType=VARCHAR}
				, CNTPNT_CD = #{cntpntCd, jdbcType=VARCHAR}
				, RSV_CNTPNT_CD = #{rsvCntpntCd, jdbcType=VARCHAR}
				, EVNT_CD = #{evntCd, jdbcType=VARCHAR}
				, EVNT_RSN_CD = #{evntRsnCd, jdbcType=VARCHAR}
				, PRDT_TYPE_CD = #{prdtTypeCd, jdbcType=VARCHAR}
				, PRDT_ID = #{rprsPrdtId, jdbcType=VARCHAR}
				, PRDT_SRL_NUM = #{prdtSrlNum, jdbcType=VARCHAR}
				, OLD_YN = #{oldYn, jdbcType=VARCHAR}
				, MYCPNY_YN = #{mycpYn, jdbcType=VARCHAR}
				, SNR_CD = #{snrCd, jdbcType=VARCHAR}
				, INV_STAT_CD = #{invStatCd, jdbcType=VARCHAR}
				, PREV_PRDT_ID = #{prvRprsPrdtId, jdbcType=VARCHAR}
				, PREV_PRDT_SRL_NUM = #{prvPrdtSrlNum, jdbcType=VARCHAR}
				, PREV_OLD_YN = #{prvOldYn, jdbcType=VARCHAR}
				, PREV_MYCPNY_YN = #{prvMycpYn, jdbcType=VARCHAR}
				, PREV_SNR_CD = #{prvSnrCd, jdbcType=VARCHAR}
				, PREV_INV_STAT_CD = #{prvInvStatCd, jdbcType=VARCHAR}
				, REQUEST_KEY = #{requestKey, jdbcType=VARCHAR}
				, TAKE_YN = #{takeYn, jdbcType=VARCHAR}
				, CHNG_ID = #{userId, jdbcType=VARCHAR}
				, CHNG_DTTM = SYSDATE

   WHEN  NOT MATCHED THEN

		INSERT (  IF_QUE_NUM                                     --인터페이스번호
				, CONTRACT_NUM                                   --가입계약번호
				, APPL_STRT_DTTM                                 --적용시작일시
				, PROC_STAT_CD                                   --처리상태코드
				, APPL_EVNT_CD                                   --적용이벤트코드
				, CNTPNT_CD                                      --접점코드
				, RSV_CNTPNT_CD                                  --예정접점코드
				, EVNT_CD                                        --이벤트코드
				, EVNT_RSN_CD                                    --이벤트사유코드
				, PRDT_TYPE_CD                                   --제품유형코드
				, PRDT_ID                                        --제품ID
				, PRDT_SRL_NUM                                   --제품일련번호
				, OLD_YN                                         --중고여부
				, MYCPNY_YN                                      --자사여부
				, SNR_CD                                         --입출고코드
				, INV_STAT_CD                                    --재고상태코드
				, PREV_PRDT_ID                                   --이전제품ID
				, PREV_PRDT_SRL_NUM                              --이전제품일련번호
				, PREV_OLD_YN                                    --이전중고여부
				, PREV_MYCPNY_YN                                 --이전자사여부
				, PREV_SNR_CD                                    --이전입출고코드
				, PREV_INV_STAT_CD                               --이전재고상태코드
				, REQUEST_KEY                                    --가입신청키
				, TAKE_YN                                        --인수여부
				, REGST_ID                                       --등록자ID
				, REG_DTTM                                       --등록일시
				, CHNG_ID                                        --변경자ID
				, CHNG_DTTM                                      --변경일시
		) VALUES (
				  #{ifQueNum, jdbcType=VARCHAR}
				, #{contractNum, jdbcType=VARCHAR}
				, #{applStrtDttm, jdbcType=VARCHAR}
				, #{procCd, jdbcType=VARCHAR}
				, #{aplEvntCd, jdbcType=VARCHAR}
				, #{cntpntCd, jdbcType=VARCHAR}
				, #{rsvCntpntCd, jdbcType=VARCHAR}
				, #{evntCd, jdbcType=VARCHAR}
				, #{evntRsnCd, jdbcType=VARCHAR}
				, #{prdtTypeCd, jdbcType=VARCHAR}
				, #{rprsPrdtId, jdbcType=VARCHAR}
				, #{prdtSrlNum, jdbcType=VARCHAR}
				, #{oldYn, jdbcType=VARCHAR}
				, #{mycpYn, jdbcType=VARCHAR}
				, #{snrCd, jdbcType=VARCHAR}
				, #{invStatCd, jdbcType=VARCHAR}
				, #{prvRprsPrdtId, jdbcType=VARCHAR}
				, #{prvPrdtSrlNum, jdbcType=VARCHAR}
				, #{prvOldYn, jdbcType=VARCHAR}
				, #{prvMycpYn, jdbcType=VARCHAR}
				, #{prvSnrCd, jdbcType=VARCHAR}
				, #{prvInvStatCd, jdbcType=VARCHAR}
				, #{requestKey, jdbcType=VARCHAR}
				, #{takeYn, jdbcType=VARCHAR}
				, #{userId, jdbcType=VARCHAR}
				, SYSDATE
				, #{userId, jdbcType=VARCHAR}
				, SYSDATE
		)

INSERT  /* LgsNstepIfMapper.insOpenHstInfo */
	INTO  LGS_OPEN_PROC_INFO (
		  CONTRACT_NUM                                   --가입계약번호
		, APPL_END_DTTM                                  --적용만료일시
		, APPL_STRT_DTTM                                 --적용시작일시
		, CNTPNT_CD                                      --접점코드
		, EVNT_CD                                        --이벤트코드
		, EVNT_RSN_CD                                    --이벤트사유코드
		, PRDT_TYPE_CD                                   --제품유형코드
		, PRDT_ID                                        --제품ID
		, PRDT_SRL_NUM                                   --제품일련번호
		, PREV_PRDT_ID                                   --이전제품ID
		, PREV_PRDT_SRL_NUM                              --이전제품일련번호
		, MYCPNY_YN                                      --자타사여부
		, INOUT_ID                                       --수불ID
		, PREV_INOUT_ID                                  --이전수불ID
		, IF_QUE_NUM                                     --인터페이스번호
		, REQUEST_KEY                                    --신청정보키
		, REGST_ID                                       --등록자ID
		, REG_DTTM                                       --등록일시
		, CHNG_ID                                        --변경자ID
		, CHNG_DTTM                                      --변경일시
) VALUES (
		  #{contractNum, jdbcType=VARCHAR}
		, #{applEndDttm, jdbcType=VARCHAR}
		, #{applStrtDttm, jdbcType=VARCHAR}
		, #{cntpntCd, jdbcType=VARCHAR}
		, #{aplEvntCd, jdbcType=VARCHAR}
		, #{evntRsnCd, jdbcType=VARCHAR}
		, #{prdtTypeCd, jdbcType=VARCHAR}
		, #{rprsPrdtId, jdbcType=VARCHAR}
		, #{prdtSrlNum, jdbcType=VARCHAR}
		, #{prvRprsPrdtId, jdbcType=VARCHAR}
		, #{prvPrdtSrlNum, jdbcType=VARCHAR}
		, #{mycpYn, jdbcType=VARCHAR}
		, #{inoutId, jdbcType=VARCHAR}
		, #{prvInoutId, jdbcType=VARCHAR}
		, #{ifQueNum, jdbcType=VARCHAR}
		, #{requestKey, jdbcType=VARCHAR}
		, #{userId, jdbcType=VARCHAR}
		, SYSDATE
		, #{userId, jdbcType=VARCHAR}
		, SYSDATE
)
